(function($){'use strict';let isSelectorMode=false;let hoveredElement=null;let heatmapActive=false;$(document).ready(function(){if(parseInt(tracklyPublicData.is_admin)===1){initAdminFloatingPanel();}});function showToast(message,type='success'){$('#trackly-stats-bar-wrapper .trackly-toast').remove();const $toast=$('<div class="trackly-toast"></div>').text(message);const bgColor=type==='error' ? 'rgba(244,63,94,0.95)':'rgba(16,185,129,0.95)';$toast.css({position:'fixed',bottom:'30px',left:'30px',background:bgColor,color:'#ffffff',padding:'14px 24px',borderRadius:'12px',boxShadow:'0 20px 40px-10px rgba(0,0,0,0.3)',backdropFilter:'blur(10px)','-webkit-backdrop-filter':'blur(10px)',zIndex:1000000,fontFamily:"'Outfit',sans-serif",fontSize:'13px',fontWeight:'600',opacity:0,transform:'translateY(20px)',transition:'all 0.3s cubic-bezier(0.175,0.885,0.32,1.275)'});$('#trackly-stats-bar-wrapper').append($toast);setTimeout(()=>{$toast.css({opacity:1,transform:'translateY(0)'});},50);setTimeout(()=>{$toast.css({opacity:0,transform:'translateY(20px)'});setTimeout(()=>$toast.remove(),300);},3500);}function initAdminFloatingPanel(){const $toggleBtn=$('#trackly-stats-toggle-btn');const $panel=$('#trackly-stats-panel');const $minimizeBtn=$('#trackly-panel-minimize-btn');const $tabs=$('.trackly-panel-tab');$toggleBtn.on('click',function(){$panel.toggleClass('active');$toggleBtn.fadeOut(200);loadPageStats();});$minimizeBtn.on('click',function(){$panel.removeClass('active');$toggleBtn.fadeIn(200);});$tabs.on('click',function(){const tabId=$(this).data('tab');$tabs.removeClass('active');$(this).addClass('active');$('.trackly-panel-tab-content').removeClass('active');$('#trackly-tab-'+tabId).addClass('active');});$('#trackly-toggle-heatmap-btn').on('click',toggleHeatmap);$('#trackly-clear-heatmap-btn').on('click',clearHeatmapDots);$('#trackly-start-selector-btn').on('click',startSelectorMode);$('#trackly-cancel-event-btn').on('click',cancelSelectorMode);$('#trackly-save-event-btn').on('click',saveCustomEvent);}function loadPageStats(){$.ajax({url:tracklyPublicData.rest_url+'/page-stats',method:'GET',data:{url:tracklyPublicData.page_url},beforeSend:function(xhr){xhr.setRequestHeader('X-WP-Nonce',tracklyPublicData.rest_nonce);},success:function(res){if(res.success&&res.report.rows&&res.report.rows.length>0){const metrics=res.report.rows[0].metricValues;const views=parseInt(metrics[0].value);const users=parseInt(metrics[1].value);const bounce=parseFloat(metrics[2].value);const duration=parseInt(metrics[3].value);$('#trackly-p-views').text(views.toLocaleString());$('#trackly-p-users').text(users.toLocaleString());$('#trackly-p-bounce').text((bounce*100).toFixed(1)+'%');const mins=Math.floor(duration/60);const secs=duration % 60;$('#trackly-p-duration').text(mins+':'+(secs<10 ? '0':'')+secs);renderStatisticalInsights(res.insights);}else{$('#trackly-p-views').text('0');$('#trackly-p-users').text('0');$('#trackly-p-bounce').text('0%');$('#trackly-p-duration').text('0:00');renderStatisticalInsights([]);}}});}function escapeHtml(string){return String(string).replace(/[&<>"']/g,function(s){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s];});}function renderStatisticalInsights(insights){const $insights=$('#trackly-ai-insights-content');$insights.empty();if(!insights||insights.length===0){$insights.append(`<div class="ai-insight-item"><span class="dashicons dashicons-info ai-icon cyan"></span><div class="ai-text"><strong>Stable Page Performance</strong><p>All visitor traffic volumes and bounce rate patterns match normal statistical distributions for the current period.</p></div></div>`);return;}insights.forEach(function(insight){let iconClass='cyan';let dashicon='dashicons-info';if(insight.type==='warning'){iconClass='purple';dashicon='dashicons-clock';}else if(insight.type==='danger'){iconClass='red';dashicon='dashicons-warning';}else if(insight.type==='success'){iconClass='cyan';dashicon='dashicons-yes-alt';}$insights.append(`<div class="ai-insight-item"><span class="dashicons ${dashicon}ai-icon ${iconClass}"></span><div class="ai-text"><strong>${escapeHtml(insight.title)}</strong><p>${escapeHtml(insight.description)}</p></div></div>`);});}function toggleHeatmap(){const $btn=$('#trackly-toggle-heatmap-btn');if(heatmapActive){clearHeatmapDots();$btn.html('<span class="dashicons dashicons-visibility"></span>Show Heatmap').removeClass('secondary');$('.heatmap-info-stats').fadeOut(200);heatmapActive=false;}else{$btn.text('Loading...');fetchHeatmapData();}}function fetchHeatmapData(){$.ajax({url:tracklyPublicData.rest_url+'/clicks',method:'GET',data:{url:tracklyPublicData.page_url},beforeSend:function(xhr){xhr.setRequestHeader('X-WP-Nonce',tracklyPublicData.rest_nonce);},success:function(res){if(res.success&&res.clicks.length>0){renderHeatmap(res.clicks);$('#trackly-heatmap-click-count').text(res.clicks.length);$('.heatmap-info-stats').fadeIn(200);$('#trackly-toggle-heatmap-btn').html('<span class="dashicons dashicons-hidden"></span>Hide Heatmap').addClass('secondary');heatmapActive=true;}else{showToast('No click records found for this page yet.','error');$('#trackly-toggle-heatmap-btn').html('<span class="dashicons dashicons-visibility"></span>Show Heatmap');}},error:function(){showToast('An error occurred while fetching click data.','error');$('#trackly-toggle-heatmap-btn').html('<span class="dashicons dashicons-visibility"></span>Show Heatmap');}});}function renderHeatmap(clicks){clearHeatmapDots();const $overlay=$('<div id="trackly-heatmap-overlay"></div>');const fragment=document.createDocumentFragment();clicks.forEach(function(click){const dot=document.createElement('div');dot.className='trackly-heatmap-dot';dot.style.left=click.click_x_pct+'%';dot.style.top=click.click_y_pct+'%';fragment.appendChild(dot);});$overlay.append(fragment);$('body').append($overlay);}function clearHeatmapDots(){$('#trackly-heatmap-overlay').remove();if(heatmapActive){$('#trackly-toggle-heatmap-btn').html('<span class="dashicons dashicons-visibility"></span>Show Heatmap').removeClass('secondary');$('.heatmap-info-stats').fadeOut(200);heatmapActive=false;}}function startSelectorMode(){isSelectorMode=true;window.tracklySelectorModeActive=true;$('#trackly-stats-panel').removeClass('active');$('body').css('cursor','crosshair');$(document).on('mouseover.tracklySelector',handleSelectorMouseOver);$(document).on('mouseout.tracklySelector',handleSelectorMouseOut);$(document).on('click.tracklySelector',handleSelectorClick);}function handleSelectorMouseOver(e){if($(e.target).closest('#trackly-stats-bar-wrapper').length)return;hoveredElement=e.target;$(hoveredElement).addClass('trackly-selector-hovered');}function handleSelectorMouseOut(e){if(hoveredElement){$(hoveredElement).removeClass('trackly-selector-hovered');hoveredElement=null;}}function handleSelectorClick(e){if($(e.target).closest('#trackly-stats-bar-wrapper').length)return;e.preventDefault();e.stopPropagation();const selector=window.tracklyGetUniqueSelector(e.target);$(e.target).removeClass('trackly-selector-hovered');exitSelectorMode();$('#trackly-selected-selector-display').text(selector);$('#trackly-p-event-name').val('');$('#trackly-builder-setup').hide();$('#trackly-builder-form').show();$('#trackly-stats-panel').addClass('active');}function cancelSelectorMode(){$('#trackly-builder-setup').show();$('#trackly-builder-form').hide();}function exitSelectorMode(){isSelectorMode=false;window.tracklySelectorModeActive=false;$('body').css('cursor','default');$(document).off('mouseover.tracklySelector');$(document).off('mouseout.tracklySelector');$(document).off('click.tracklySelector');}function saveCustomEvent(){const selector=$('#trackly-selected-selector-display').text();const eventName=$('#trackly-p-event-name').val().trim();if(!eventName){showToast('Please enter a valid event name.','error');return;}if(/[<>]/.test(selector)){showToast('Invalid CSS Selector.','error');return;}$.ajax({url:tracklyPublicData.rest_url+'/save-event',method:'POST',contentType:'application/json',data:JSON.stringify({selector:selector,event_name:eventName}),beforeSend:function(xhr){xhr.setRequestHeader('X-WP-Nonce',tracklyPublicData.rest_nonce);},success:function(res){if(res.success){showToast(`Success!"${eventName}" GA4 event saved.`,'success');cancelSelectorMode();}else{showToast('An error occurred while saving the event.','error');}},error:function(){showToast('A server error occurred.','error');}});}})(jQuery);